create table if not exists intelligence_predictions (id uuid primary key, tenant_id uuid not null, metric text not null, horizon_days integer not null, predicted_value numeric not null, confidence numeric not null, created_at timestamptz not null default now());
create table if not exists intelligence_recommendations (id uuid primary key, tenant_id uuid not null, category text not null, rationale text not null, expected_impact numeric not null, status text not null default 'proposed', created_at timestamptz not null default now());
create table if not exists intelligence_anomalies (id uuid primary key, tenant_id uuid not null, anomaly_type text not null, severity text not null, details jsonb not null default '{}'::jsonb, detected_at timestamptz not null default now());
create table if not exists intelligence_workflow_optimizations (id uuid primary key, tenant_id uuid not null, workflow_id uuid not null, suggestion text not null, approved boolean not null default false, created_at timestamptz not null default now());
create table if not exists intelligence_copilot_sessions (id uuid primary key, tenant_id uuid not null, copilot_type text not null, prompt text not null, response text not null, created_at timestamptz not null default now());
